package main

import (
	"fmt"
	"log"
	"net/http"
	"os"
	"path"
	"strings"
)

func main() {
	// Create the HTTP handler
	http.HandleFunc("/upload", handleUpload)

	// Start the server
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal(err)
	}
}

func handleUpload(w http.ResponseWriter, r *http.Request) {
	// Parse the multipart form
	r.ParseMultipartForm(32 << 20)

	// Get the file from the request body
	file, _, err := r.FormFile("file")
	if err != nil {
		log.Println(err)
		http.Error(w, "Error uploading file", http.StatusInternalServerError)
		return
	}

	// Get the file extension from the filename
	filename := filepath.Base(file.Filename)
	ext := strings.ToLower(filepath.Ext(filename))

	// Check if the file type is supported
	supportedTypes := []string{".jpg", ".png", ".pdf", ".docx", ".zip"}
	if !contains(supportedTypes, ext) {
		log.Println("Unsupported file type:", ext)
		http.Error(w, "Unsupported file type", http.StatusBadRequest)
		return
	}

	// Save the file to a public directory
	dir := "public"
	os.MkdirAll(dir, 0755)
	filePath := path.Join(dir, filename)
	if err := os.Rename(file.Filename, filePath); err != nil {
		log.Println(err)
		http.Error(w, "Error saving file", http.StatusInternalServerError)
		return
	}

	// Return the file path
	fmt.Fprintf(w, "%s\n", filePath)
}

func contains(slice []string, val string) bool {
	for _, item := range slice {
		if item == val {
			return true
		}
	}
	return false
}